function parseField(val) {
  if (!val) return null;
  if (val.nullValue !== undefined) return null;
  if (val.stringValue !== undefined) return val.stringValue;
  if (val.integerValue !== undefined) return parseInt(val.integerValue, 10);
  if (val.doubleValue !== undefined) return parseFloat(val.doubleValue);
  if (val.booleanValue !== undefined) return val.booleanValue;
  if (val.timestampValue !== undefined) return val.timestampValue;
  if (val.mapValue) {
    const obj = {};
    for (const [k, v] of Object.entries(val.mapValue.fields || {})) {
      obj[k] = parseField(v);
    }
    return obj;
  }
  if (val.arrayValue) {
    return (val.arrayValue.values || []).map(parseField);
  }
  return null;
}

function parseDoc(doc) {
  const id = (doc.name || '').split('/').pop();
  const fields = {};
  for (const [k, v] of Object.entries(doc.fields || {})) {
    fields[k] = parseField(v);
  }
  return { id, ...fields };
}

function parseDateBR(str) {
  if (!str || typeof str !== 'string') return null;
  const br = str.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (br) {
    const [, d, m, y] = br;
    return new Date(`${y}-${m}-${d}T00:00:00Z`);
  }
  const iso = new Date(str);
  if (!isNaN(iso.getTime())) return iso;
  return null;
}

function diffDays(fromDate, toDate) {
  const ms = toDate.getTime() - fromDate.getTime();
  return Math.ceil(ms / (1000 * 60 * 60 * 24));
}

function normalizeText(str) {
  return String(str || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim().toLowerCase();
}

// 1. Coleta de Dados
const lotesDocs    = $('Lotes').first().json.documents    || [];
const alertasDocs  = $('Alertas').first().json.documents  || [];
const tarefasDocs  = $('Tarefas').first().json.documents  || [];
const limitesDocs  = $('Limites').first().json.documents  || [];
const catalogoDocs = $('Catalogo').first().json.documents || [];

const lotesRaw    = lotesDocs.map(parseDoc);
const alertasRaw  = alertasDocs.map(parseDoc);
const tarefasRaw  = tarefasDocs.map(parseDoc);
const limitesRaw  = limitesDocs.map(parseDoc);
const catalogoRaw = catalogoDocs.map(parseDoc);

const hoje = new Date();
hoje.setUTCHours(0, 0, 0, 0);

// 2. Prevenção de Duplicatas (Lendo tarefas pendentes existentes)
const lotesJaBloqueados    = new Set();
const produtosJaBloqueados = new Set();
const alertasJaBloqueados  = new Set();

tarefasRaw.forEach(tarefa => {
  const s = normalizeText(tarefa.status || '');
  if (s.includes('pendente')) {
    if (tarefa.loteId)      lotesJaBloqueados.add(tarefa.loteId);
    if (tarefa.loteAlvo)    lotesJaBloqueados.add(tarefa.loteAlvo);
    if (tarefa.produto)     produtosJaBloqueados.add(normalizeText(tarefa.produto));
    if (tarefa.produtoAlvo) produtosJaBloqueados.add(normalizeText(tarefa.produtoAlvo));
    if (tarefa.alertaId)    alertasJaBloqueados.add(tarefa.alertaId);
  }
});

const catalogo = {};
for (const c of catalogoRaw) catalogo[c.id] = c.nome || c.id;

const limites = {};
for (const l of limitesRaw) limites[l.id] = { min: Number(l.min || 0), max: Number(l.max || 0) };

const tarefasParaCriar = [];
const lotesAtivos = lotesRaw.filter(l => normalizeText(l.status) === 'ativo');

// 3. Análise de Estoque e Vencimentos (Agrupado por Produto)
const analiseEstoque = {};

for (const lote of lotesAtivos) {
  const nomeProduto = lote.item || lote.produto; // Suporte para possíveis variações de nome do campo
  if (!nomeProduto) continue;

  const nomeNorm = normalizeText(nomeProduto);
  if (!analiseEstoque[nomeNorm]) {
    analiseEstoque[nomeNorm] = { total: 0, vencido: 0, expirando7d: 0, nomeOriginal: nomeProduto };
  }

  const peso = typeof lote.pesoKg === 'number' ? lote.pesoKg : Number(lote.pesoKg || 0);
  analiseEstoque[nomeNorm].total += peso;

  const validadeDate = parseDateBR(lote.validade || lote.dataValidade);
  if (validadeDate) {
    const dias = diffDays(hoje, validadeDate);

    // GERAÇÃO TAREFA DE DESCARTE INDIVIDUAL POR LOTE
    if (dias < 0) {
      analiseEstoque[nomeNorm].vencido += peso;
      const chave = lote.masterLote || lote.id;
      if (!lotesJaBloqueados.has(chave)) {
        tarefasParaCriar.push({
          tipo: 'descarte',
          produto: analiseEstoque[nomeNorm].nomeOriginal,
          produtoAlvo: analiseEstoque[nomeNorm].nomeOriginal,
          loteId: chave,
          status: 'pendente',
          instrucao: `Status Vencido (Descartar imediatamente): Lote ${chave} venceu há ${Math.abs(dias)} dia(s). Remover de circulação.`,
          criadoEm: new Date().toISOString(),
          criadoPor: 'sistema_autonomo'
        });
        lotesJaBloqueados.add(chave);
      }
    } else if (dias <= 7) {
      analiseEstoque[nomeNorm].expirando7d += peso;
    }
  }
}

// 4. Geração de Tarefas de Reposição (Baseado nos Limites e Projeção)
for (const [idConfig, cfg] of Object.entries(limites)) {
  const nomeCat = catalogo[idConfig] || idConfig;
  const nomeNorm = normalizeText(nomeCat);

  if (produtosJaBloqueados.has(nomeNorm)) continue; // Já tem tarefa de reposição aberta para este produto

  const info = analiseEstoque[nomeNorm] || { total: 0, vencido: 0, expirando7d: 0, nomeOriginal: nomeCat };

  const estoqueValido = info.total - info.vencido; // O que realmente pode ser usado hoje
  const estoqueProjetado = estoqueValido - info.expirando7d; // O que vai sobrar na próxima semana

  let instrucao = '';
  let qtdRequerida = 0;
  let criarReposicao = false;

  // Lógica 1: Caiu abaixo do mínimo AGORA
  if (estoqueValido < cfg.min) {
    criarReposicao = true;
    qtdRequerida = cfg.max - estoqueValido;
    instrucao = `Status Urgente (Crítico): O estoque válido atual (${estoqueValido.toFixed(1)}kg) está abaixo do mínimo exigido (${cfg.min}kg). Repor com urgência para atingir a meta.`;
  } 
  // Lógica 2: Vai cair abaixo do mínimo EM BREVE por causa de vencimentos
  else if (estoqueProjetado < cfg.min && info.expirando7d > 0) {
    criarReposicao = true;
    qtdRequerida = cfg.max - estoqueProjetado;
    instrucao = `Status Alerta (Atenção/Vence em Breve): Nos próximos 7 dias, ${info.expirando7d.toFixed(1)}kg irão vencer. Isso fará o estoque cair para ${estoqueProjetado.toFixed(1)}kg (abaixo do mínimo de ${cfg.min}kg). Produzir lote de reposição preventivo.`;
  }

  if (criarReposicao) {
    tarefasParaCriar.push({
      tipo: 'reposicao',
      produto: info.nomeOriginal,
      produtoAlvo: info.nomeOriginal,
      quantidadeRequerida: Math.ceil(qtdRequerida), // Arredonda pra cima
      status: 'pendente',
      instrucao: instrucao,
      criadoEm: new Date().toISOString(),
      criadoPor: 'sistema_autonomo'
    });
    produtosJaBloqueados.add(nomeNorm); // Evita duplicatas nesta mesma execução
  }
}

// 5. Geração de Tarefas de Manutenção (Alertas)
for (const alerta of alertasRaw.filter(a => normalizeText(a.status) === 'pendente')) {
  if (!alertasJaBloqueados.has(alerta.id)) {
    tarefasParaCriar.push({
      tipo: 'manutencao',
      produto: alerta.tipoAlerta || 'Sensor', // O app usa "produto" para exibir o local da manutenção
      produtoAlvo: alerta.tipoAlerta || 'Sensor',
      status: 'pendente',
      instrucao: `Status Urgente (Crítico): Alerta detectado no sistema. \nLocal/Sensor: ${alerta.id}\nDescrição: ${alerta.descricao || 'Verificar equipamento.'}`,
      criadoEm: new Date().toISOString(),
      criadoPor: 'sistema_autonomo'
    });
    alertasJaBloqueados.add(alerta.id);
  }
}

// 6. Retorno final para o Request HTTP do n8n
if (tarefasParaCriar.length === 0) {
  return [{ json: { nenhuma_tarefa: true } }];
}

return tarefasParaCriar.map(t => ({ json: t }));
